import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;

public class Main {
  public static void main(String[] args) {
    try {
      BufferedWriter writer = new BufferedWriter(new FileWriter("output.txt"));
      writer.write("Salam, dünya!\n");
      writer.write("Bu bir testdir.");
      writer.close();
      System.out.println("Fayla yazıldı.");
    } catch (IOException e) {
      System.out.println("Səhv: " + e.getMessage());
    }
  }
}
// Çıxış: Fayla yazıldı.
// (Fayl sistemində 'output.txt' adlı fayl yaradılır və mətn yazılır)

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;

public class Main {
  public static void main(String[] args) {
    try (BufferedReader reader = new BufferedReader(new FileReader("input.txt"))) {
      String line;
      while ((line = reader.readLine()) != null) {
        System.out.println("Oxunan sətir: " + line);
      }
    } catch (IOException e) {
      System.out.println("Səhv: " + e.getMessage());
    }
  }
}
// Çıxış: (Əgər 'input.txt' mövcuddursa, onun sətirləri oxunur, əks halda səhv mesajı göstərilir)

